export const modelsGetProviderResponseModelDeploymentIdMax = 255;

export const modelsGetProviderResponseAuthHeaderFormatMax = 1024;

export const ModelsGetProviderResponse = zod
  .object({
    id: zod.string().optional().describe('Unique identifier for the model provider'),
    name: zod
      .string()
      .max(modelsGetProviderResponseNameMax)
      .regex(modelsGetProviderResponseNameRegExp)
      .describe(
        'Name of the entity. Name\/workspace combo must be unique across all entities. Allowed characters: letters (a-z, A-Z), digits (0-9), underscores, hyphens, and dots.'
      ),
    workspace: zod
      .string()
      .max(modelsGetProviderResponseWorkspaceMax)
      .regex(modelsGetProviderResponseWorkspaceRegExp)
      .describe(
        'The workspace of the entity. Allowed characters: letters (a-z, A-Z), digits (0-9), underscores, hyphens, and dots.'
      ),
    project: zod
      .string()
      .max(modelsGetProviderResponseProjectMax)
      .regex(modelsGetProviderResponseProjectRegExp)
      .optional()
      .describe('The URN of the project associated with this entity.'),
    created_at: zod.string().datetime({}).describe('The timestamp of model entity creation'),
    updated_at: zod.string().datetime({}).describe('The timestamp of the last model entity update'),
    description: zod
      .string()
      .max(modelsGetProviderResponseDescriptionMax)
      .optional()
      .describe('Optional description of the model provider'),
    host_url: zod
      .string()
      .max(modelsGetProviderResponseHostUrlMax)
      .describe('The network endpoint URL for the model provider'),
    api_key_secret_name: zod
      .string()
      .max(modelsGetProviderResponseApiKeySecretNameMax)
      .optional()
      .describe('Reference to the API key stored in Secrets service'),
    served_models: zod
      .array(
        zod
          .object({
            model_entity_id: zod
              .string()
              .max(modelsGetProviderResponseServedModelsItemModelEntityIdMax)
              .describe("Model Entity identifier as workspace\/name (e.g., 'my-ws\/my-model')"),
            served_model_name: zod
              .string()
              .max(modelsGetProviderResponseServedModelsItemServedModelNameMax)
              .describe(
                "The actual model name to send to the backend endpoint in the 'model' field"
              ),
          })
          .describe("Mapping between a Model Entity and how it's served by this provider.")
      )
      .optional()
      .describe('List of models served by this provider with routing information for IGW'),
    enabled_models: zod
      .array(zod.string())
      .optional()
      .describe(
        'Optional list of specific models to enable from this provider. If not set, all discovered models are enabled.'
      ),
    status: zod
      .enum(['UNKNOWN', 'CREATED', 'PENDING', 'READY', 'ERROR', 'DELETING', 'DELETED', 'LOST'])
      .describe('Status enum for ModelProvider objects.')
      .default(modelsGetProviderResponseStatusDefault)
      .describe('Current status of the model provider, populated by models service'),
    status_message: zod
      .string()
      .max(modelsGetProviderResponseStatusMessageMax)
      .default(modelsGetProviderResponseStatusMessageDefault)
      .describe('Detailed status message, populated by models service'),
    default_extra_body: zod
      .record(zod.string(), zod.unknown())
      .optional()
      .describe(
        'Default body parameters for inference requests. Can be overridden by user requests.'
      ),
    default_extra_headers: zod
      .record(zod.string(), zod.string())
      .optional()
      .describe('Default headers for inference requests. Can be overridden by user requests.'),
    required_extra_body: zod
      .record(zod.string(), zod.unknown())
      .optional()
      .describe(
        'Required body parameters for inference requests. Cannot be overridden by user requests.'
      ),
    required_extra_headers: zod
      .record(zod.string(), zod.string())
      .optional()
      .describe('Required headers for inference requests. Cannot be overridden by user requests.'),
    model_deployment_id: zod
      .string()
      .max(modelsGetProviderResponseModelDeploymentIdMax)
      .optional()
      .describe(
        'Optional reference to the ModelDeployment ID if this provider was auto-created for a deployment'
      ),
    auth_context: zod
      .object({
        principal_id: zod.string().describe("The principal's unique identifier"),
        principal_email: zod.string().optional().describe("The principal's email address"),
        principal_groups: zod
          .array(zod.string())
          .optional()
          .describe('Groups the principal belongs to'),
        principal_on_behalf_of: zod
          .string()
          .optional()
          .describe('If acting on behalf of another principal, their principal ID'),
        principal_on_behalf_of_groups: zod
          .array(zod.string())
          .optional()
          .describe('Groups the on-behalf-of principal belongs to'),
        principal_on_behalf_of_email: zod
          .string()
          .optional()
          .describe("The on-behalf-of principal's email address"),
      })
      .describe(
        "Auth context captured at resource creation for delegated access.\n\nStores a snapshot of the creating principal's identity so that controllers\ncan later act on their behalf (e.g., accessing secrets)."
      )
      .optional()
      .describe('Auth context captured at provider creation.'),
    auth_header_format: zod
      .string()
      .max(modelsGetProviderResponseAuthHeaderFormatMax)
      .optional()
      .describe(
        "Jinja2 template string controlling how the API key secret is sent to the upstream. Must contain exactly one variable named `auth_secret`, which is substituted with the resolved secret value at request time. Example: `'X-Api-Key: {{ auth_secret }}'`. If not set, defaults to `'Authorization: Bearer {{ auth_secret }}'`."
      ),
  })
  .describe(
    'A ModelProvider defines a reachable network endpoint that provides an inference\nservice for one or more Model Entities. Examples of Model Providers include\nOpenAI, NIMs, Bedrock, NVIDIA Build, etc. A ModelProvider may be provisioned\nautomatically by Models Controller for ModelDeployments, or it may be provisioned\nmanually by an end user for an endpoint that does not have its lifecycle managed\nby models service (like an external provider.)\n\nThe unique identifier for a ModelProvider is the combination of workspace\/name.'
  );

/**
 * Delete a model provider by workspace and name.
 * @summary Delete ModelProvider
 */
export const ModelsDeleteProviderParams = zod.object({
  workspace: zod.string(),
  name: zod.string(),
});

/**
 * Update status-related fields of a model provider.

This endpoint supports partial updates for fields managed by Models Controller:
- model_deployment_id
- served_models
- status
- status_message

If status is provided without status_message, status_message will be set to empty string.
 * @summary Update ModelProvider Status Fields
 */
export const ModelsUpdateProviderStatusParams = zod.object({
  workspace: zod.string(),
  name: zod.string(),
});

export const modelsUpdateProviderStatusBodyModelDeploymentIdMax = 255;

export const modelsUpdateProviderStatusBodyServedModelsItemModelEntityIdMax = 255;

export const modelsUpdateProviderStatusBodyServedModelsItemServedModelNameMax = 255;

export const modelsUpdateProviderStatusBodyStatusMessageMax = 1000;

export const ModelsUpdateProviderStatusBody = zod
  .object({
    model_deployment_id: zod
      .string()
      .max(modelsUpdateProviderStatusBodyModelDeploymentIdMax)
      .optional()
      .describe(
        'Reference to the ModelDeployment ID if this provider is associated with a deployment'
      ),
    served_models: zod
      .array(
        zod
          .object({
            model_entity_id: zod
              .string()
              .max(modelsUpdateProviderStatusBodyServedModelsItemModelEntityIdMax)
              .describe("Model Entity identifier as workspace\/name (e.g., 'my-ws\/my-model')"),
            served_model_name: zod
              .string()
              .max(modelsUpdateProviderStatusBodyServedModelsItemServedModelNameMax)
              .describe(
                "The actual model name to send to the backend endpoint in the 'model' field"
              ),
          })
          .describe("Mapping between a Model Entity and how it's served by this provider.")
      )
      .optional()
      .describe('List of models served by this provider with routing information for IGW'),
    status: zod
      .enum(['UNKNOWN', 'CREATED', 'PENDING', 'READY', 'ERROR', 'DELETING', 'DELETED', 'LOST'])
      .describe('Status enum for ModelProvider objects.')
      .optional()
      .describe('Status of the model provider'),
    status_message: zod
      .string()
      .max(modelsUpdateProviderStatusBodyStatusMessageMax)
      .optional()
      .describe(
        'Status message. If status is provided without status_message, defaults to empty string.'
      ),
  })
  .describe(
    'Request model for updating ModelProvider status and autodiscovery fields.\n\nThis endpoint supports partial updates for fields managed by Models Controller.'
  );

